program.STSource:
(* start weighing process for material B*)
(* opening valve B *)

if Flapp.et = t#5s and not Flapp_b then
	Flapp_closed:=true;
	Flapp_a:=false;
	set (valve_b_open);
	reset (Weighing_B_done);
	reset (valve_b_closed);
end_if;

(* filling weight till demandet value *)

if valve_b_open and re (sec) and Weighing_material_b<=material_b_value 
	then
	inc_int (Weighing_material_b);
end_if;

(* close valve B if demandet value reached *)
(* set internal bit flapp B => for operator screen *)

if weighing_material_b=material_b_value 
	then
	reset (valve_b_open);
	valve_b_closed:=true;
	set (Weighing_B_done);
	Flapp_b:=true;	
	if flapp_b 
		then
		weighing_material_b:=0;
		set (Material_b_in);
	end_if;
end_if;

(* start process mixing *)

if Flapp.et = t#5s and not Flapp_open 
	then
	flapp_b:=false;
	set (ready_to_mix);
end_if;

(* calculating material values vor operator screen *)

Material_A:=cv_material_a_2;
if cv_material_b_2=0 
	then
	material_b:=1000;
	cv_material_b:=1000;
	else 
	Material_B:=cv_material_b_2;
end_if;

if valve_a_open 
	then
	cv_material_a_2:=cv_material_a-weighing_material_a;
end_if;

if valve_a_closed 
	then
	cv_material_a:=Cv_material_a_2;
end_if;

if valve_b_open 
	then
	cv_material_b_2:=cv_material_b-weighing_material_b;
end_if;

if valve_b_closed then
	cv_material_b:=cv_material_b_2;
end_if;
